-- Rollback for 20260722100300_seed_reference_foods.sql
-- Data-only rollback (no schema objects created by the forward migration) --
-- removes exactly the fixed-UUID illustrative seed rows this migration
-- inserted. Safe to re-run (IF EXISTS-equivalent via WHERE id = ANY(...),
-- which simply matches zero rows if already removed).
--
-- Order matters: food_nutrients/food_servings reference foods via FK
-- (ON DELETE CASCADE), so deleting the seeded foods rows alone would already
-- cascade-remove their servings/nutrients -- both are still deleted
-- explicitly first here for clarity and to avoid relying on cascade
-- behavior in a rollback script (production-standards: don't assume the
-- "intended" path is the only path this script will ever be run against).

delete from public.food_nutrients
where id = any(array[
  'c0000000-0000-4000-8000-000000000001', 'c0000000-0000-4000-8000-000000000002',
  'c0000000-0000-4000-8000-000000000003', 'c0000000-0000-4000-8000-000000000004',
  'c0000000-0000-4000-8000-000000000005', 'c0000000-0000-4000-8000-000000000006'
]::uuid[]);

